ALTER TABLE "participant_credit_allocation" ADD CONSTRAINT "participant_credit_allocation_user_id_user_id_fk" FOREIGN KEY ("user_id") REFERENCES "public"."user"("id") ON DELETE cascade ON UPDATE no action;
ALTER TABLE "team_credit_allocation" ADD CONSTRAINT "team_credit_allocation_credit_pool_id_credit_pool_id_fk" FOREIGN KEY ("credit_pool_id") REFERENCES "public"."credit_pool"("id") ON DELETE cascade ON UPDATE no action;
