-- ============================================================
-- 0009: mentor_request_status enum; mentor_request table
-- ============================================================

CREATE TYPE "public"."mentor_request_status" AS ENUM('pending', 'assigned', 'matched', 'completed', 'cancelled');

CREATE TABLE "mentor_request" (
	"id" text PRIMARY KEY NOT NULL,
	"team_id" integer NOT NULL,
	"status" "mentor_request_status" DEFAULT 'pending' NOT NULL,
	"assigned_mentor_id" text,
	"accepted_mentor_id" text,
	"declined_mentor_ids" text[] DEFAULT '{}' NOT NULL,
	"requested_at" timestamp with time zone DEFAULT now() NOT NULL,
	"assigned_at" timestamp with time zone,
	"matched_at" timestamp with time zone,
	"completed_at" timestamp with time zone,
	"cancelled_at" timestamp with time zone
);

ALTER TABLE "mentor_request" ADD CONSTRAINT "mentor_request_team_id_team_id_fk" FOREIGN KEY ("team_id") REFERENCES "public"."team"("id") ON DELETE cascade ON UPDATE no action;
ALTER TABLE "mentor_request" ADD CONSTRAINT "mentor_request_assigned_mentor_id_user_id_fk" FOREIGN KEY ("assigned_mentor_id") REFERENCES "public"."user"("id") ON DELETE set null ON UPDATE no action;
ALTER TABLE "mentor_request" ADD CONSTRAINT "mentor_request_accepted_mentor_id_user_id_fk" FOREIGN KEY ("accepted_mentor_id") REFERENCES "public"."user"("id") ON DELETE set null ON UPDATE no action;

CREATE INDEX "mentor_request_team_idx" ON "mentor_request" USING btree ("team_id");
CREATE INDEX "mentor_request_status_idx" ON "mentor_request" USING btree ("status");
CREATE INDEX "mentor_request_assigned_mentor_idx" ON "mentor_request" USING btree ("assigned_mentor_id");
CREATE INDEX "mentor_request_accepted_mentor_idx" ON "mentor_request" USING btree ("accepted_mentor_id");

-- ============================================================
-- 0010: team scoring adjustment columns
-- ============================================================

ALTER TABLE "team" ADD COLUMN "judge_count_override" integer;
ALTER TABLE "team" ADD COLUMN "late_submission_penalty_points" integer DEFAULT 0 NOT NULL;
ALTER TABLE "team" ADD CONSTRAINT "team_judge_count_override_check" CHECK ("team"."judge_count_override" is null or ("team"."judge_count_override" >= 1 and "team"."judge_count_override" <= 100));
ALTER TABLE "team" ADD CONSTRAINT "team_late_penalty_range_check" CHECK ("team"."late_submission_penalty_points" >= 0 and "team"."late_submission_penalty_points" <= 100);

-- ============================================================
-- 0011: team final_score_override column
-- ============================================================

ALTER TABLE "team" ADD COLUMN "final_score_override" real;
ALTER TABLE "team" ADD CONSTRAINT "team_final_score_override_range_check" CHECK ("team"."final_score_override" is null or ("team"."final_score_override" >= 0 and "team"."final_score_override" <= 100));
